bool is_leap_year(int year) {
	if (year % 400 == 0)
		return true;

	else if ((year % 4 == 0) && (year % 100 != 0))
		return true;

	else
		return false;
}

int count_year(int year) {
	int count = 0;

	if (is_leap_year(year)) {
		do {
			if (is_leap_year(year))
				count += 2;
			else
				count += 1;
			year++;
		} while (((count % 7 != 0) || (!is_leap_year(year)))) ;

	}

	else {
		do {
			if (is_leap_year(year))
				count += 2;
			else
				count += 1;
			year++;

		} while ((count % 7 != 0)|| (is_leap_year(year)));
	}

	return year;



}

